class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)
        if root_i != root_j:
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_i] > self.rank[root_j]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1

def swim_in_rising_water(grid):
    n = len(grid)
    uf = UnionFind(n * n)
    indices = sorted(range(n * n), key=lambda i: grid[i // n][i % n])
    visited = [False] * (n * n)

    def get_neighbors(i):
        row, col = i // n, i % n
        neighbors = []
        if row > 0:
            neighbors.append(i - n)
        if row < n - 1:
            neighbors.append(i + n)
        if col > 0:
            neighbors.append(i - 1)
        if col < n - 1:
            neighbors.append(i + 1)
        return neighbors

    for index in indices:
        visited[index] = True
        for neighbor in get_neighbors(index):
            if visited[neighbor]:
                uf.union(index, neighbor)
        if uf.find(0) == uf.find(n * n - 1):
            return grid[index // n][index % n]
    return -1
